class Solution:
    def minSumOfLengths(self, arr, target):
        n = len(arr)
        subs = []
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += arr[j]
                if s == target:
                    subs.append((i, j))
        best = float('inf')
        for i1, j1 in subs:
            for i2, j2 in subs:
                if j1 < i2 or j2 < i1:
                    best = min(best, (j1 - i1 + 1) + (j2 - i2 + 1))
        return best if best < float('inf') else -1

