class Solution:
    def minSumOfLengths(self, arr, target):
        n = len(arr)
        prefix = 0
        seen = {0: -1}
        INF = float('inf')
        best = [INF] * n
        ans = INF
        for r in range(n):
            prefix += arr[r]
            cur_len = INF
            if (prefix - target) in seen:
                l = seen[prefix - target]
                cur_len = r - l
                if l >= 0 and best[l] < INF:
                    ans = min(ans, cur_len + best[l])
            prev_best = best[r - 1] if r > 0 else INF
            best[r] = min(prev_best, cur_len)
            seen[prefix] = r
        return ans if ans < INF else -1

