var minSumOfLengths = function(arr, target) {
    const n = arr.length;
    let prefix = 0;
    const seen = new Map([[0, -1]]);
    const INF = Infinity;
    const best = new Array(n).fill(INF);
    let ans = INF;
    for (let r = 0; r < n; r++) {
        prefix += arr[r];
        let curLen = INF;
        if (seen.has(prefix - target)) {
            const l = seen.get(prefix - target);
            curLen = r - l;
            if (l >= 0 && best[l] < INF) {
                ans = Math.min(ans, curLen + best[l]);
            }
        }
        const prevBest = r > 0 ? best[r - 1] : INF;
        best[r] = Math.min(prevBest, curLen);
        seen.set(prefix, r);
    }
    return ans < INF ? ans : -1;
};
